import React, { useState } from 'react';

function MovieCard({ movie, delay = 0 }) {
    const [imgError, setImgError] = useState(false);

    const fallbackPoster = "https://images.unsplash.com/photo-1536440136628-849c177e76a1?auto=format&fit=crop&w=500&q=80";

    return (
        <div
            className="movie-card"
            style={{ animationDelay: `${delay}s` }}
        >
            <div className="card-poster-wrap">
                <img
                    src={imgError ? fallbackPoster : (movie.poster || fallbackPoster)}
                    alt={movie.title}
                    className="card-poster"
                    onError={() => setImgError(true)}
                    loading="lazy"
                />
                {/* Rating badge */}
                {movie.rating > 0 && (
                    <div className="card-rating-badge">
                        <span className="badge-star">★</span>
                        <span>{movie.rating.toFixed(1)}</span>
                    </div>
                )}
                {/* Hover overlay with overview */}
                <div className="card-overlay">
                    <p className="card-overview">
                        {movie.overview
                            ? movie.overview.length > 150
                                ? movie.overview.substring(0, 150) + '...'
                                : movie.overview
                            : 'No summary available.'
                        }
                    </p>
                </div>
            </div>
            <div className="card-info">
                <h4 className="card-title">{movie.title}</h4>
                {movie.rating > 0 && (
                    <div className="card-rating-row">
                        <span className="card-stars">{'★'.repeat(Math.round(movie.rating / 2))}{'☆'.repeat(5 - Math.round(movie.rating / 2))}</span>
                    </div>
                )}
            </div>
        </div>
    );
}

export default MovieCard;
